import React from 'react';
import { store } from './store';
import { Counter } from './Counter';
import { Todos } from './Todos';
import './styles.css';

const { StoreProvider } = store;

export default function App() {
  return (
    <StoreProvider>
      <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif', maxWidth: '32rem' }}>
        <h1 style={{ marginBottom: '1.5rem' }}>Mini Redux</h1>
        <Counter />
        <hr style={{ margin: '1.5rem 0', borderColor: '#e5e7eb' }} />
        <Todos />
      </div>
    </StoreProvider>
  );
}

import React from 'react';
import { store } from './store';

const { useSelector, useDispatch } = store;

export const Counter: React.FC = () => {
  const count = useSelector((s: any) => s.counter);
  const dispatch = useDispatch();

  return (
    <div>
      <h2 style={{ marginBottom: '0.75rem' }}>Counter</h2>
      <p data-testid="counter-value" style={{ fontSize: '2rem', fontWeight: 700 }}>{count}</p>
      <div style={{ display: 'flex', gap: '0.5rem', marginTop: '0.5rem' }}>
        <button data-testid="increment" className="btn" onClick={() => dispatch({ type: 'INCREMENT' })}>+</button>
        <button data-testid="decrement" className="btn" onClick={() => dispatch({ type: 'DECREMENT' })}>−</button>
        <button data-testid="reset-counter" className="btn btn--ghost" onClick={() => dispatch({ type: 'RESET' })}>Reset</button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { store } from './store';

const { useSelector, useDispatch } = store;

export const Todos: React.FC = () => {
  const todos = useSelector((s: any) => s.todos) as { text: string; done: boolean }[];
  const dispatch = useDispatch();
  const [text, setText] = useState('');

  const handleAdd = () => {
    if (!text.trim()) return;
    dispatch({ type: 'ADD_TODO', text: text.trim() });
    setText('');
  };

  return (
    <div>
      <h2 style={{ marginBottom: '0.75rem' }}>Todos</h2>
      <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '0.75rem' }}>
        <input data-testid="todo-input" className="todo-input" value={text} onChange={e => setText(e.target.value)} placeholder="New todo…" />
        <button data-testid="add-todo" className="btn" onClick={handleAdd}>Add</button>
      </div>
      <p data-testid="todo-count" style={{ fontSize: '0.8125rem', color: '#6b7280' }}>{todos.length} item(s)</p>
      <ul className="todo-list">
        {todos.map((t, i) => (
          <li key={i} data-testid={`todo-${i}`} className={`todo-item${t.done ? ' todo-item--done' : ''}`}>
            <button data-testid={`toggle-${i}`} className="todo-toggle" onClick={() => dispatch({ type: 'TOGGLE_TODO', index: i })}>
              {t.done ? '✓' : '○'}
            </button>
            <span>{t.text}</span>
            <button data-testid={`remove-${i}`} className="todo-remove" onClick={() => dispatch({ type: 'REMOVE_TODO', index: i })}>✕</button>
          </li>
        ))}
      </ul>
    </div>
  );
};

import React, { createContext, useContext, useReducer, useMemo } from 'react';

