// --- createStore ---
// TODO: Implement createStore
// Returns { StoreProvider, useSelector, useDispatch }
export function createStore<S>(rootReducer: Reducer<S>, initialState: S, middleware?: Middleware) {
  const StoreContext = createContext<{ state: S; dispatch: React.Dispatch<Action> } | null>(null);

  const StoreProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [state, rawDispatch] = useReducer(rootReducer, initialState);

    // TODO: Wrap dispatch with middleware if provided
    const dispatch = rawDispatch;

    const value = useMemo(() => ({ state, dispatch }), [state, dispatch]);
