import { createStore, combineReducers, Action } from './miniRedux';

// --- Counter Reducer ---
function counterReducer(state: number = 0, action: Action): number {
  switch (action.type) {
    case 'INCREMENT': return state + 1;
    case 'DECREMENT': return state - 1;
    case 'RESET': return 0;
    default: return state;
  }
}

// --- Todos Reducer ---
interface Todo { text: string; done: boolean; }

function todosReducer(state: Todo[] = [], action: Action): Todo[] {
  switch (action.type) {
    case 'ADD_TODO': return [...state, { text: action.text, done: false }];
    case 'TOGGLE_TODO': return state.map((t, i) => i === action.index ? { ...t, done: !t.done } : t);
    case 'REMOVE_TODO': return state.filter((_, i) => i !== action.index);
    default: return state;
  }
}

const rootReducer = combineReducers({ counter: counterReducer, todos: todosReducer });

export const store = createStore(
  rootReducer,
  { counter: 0, todos: [] as Todo[] },
);

