import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import { combineReducers } from './miniRedux';

describe('combineReducers', () => {
  it('combines multiple reducers', () => {
    const a = (s = 0, action: any) => action.type === 'INC' ? s + 1 : s;
    const b = (s: string[] = [], action: any) => action.type === 'PUSH' ? [...s, action.val] : s;
    const root = combineReducers({ count: a, items: b });
    let state = root({ count: 0, items: [] }, { type: 'INC' });
    expect(state.count).toBe(1);
    expect(state.items).toEqual([]);
    state = root(state, { type: 'PUSH', val: 'x' });
    expect(state.count).toBe(1);
    expect(state.items).toEqual(['x']);
  });
});

describe('Mini Redux integration', () => {
  function renderApp() {
    const App = require('./App').default;
    render(<App />);
  }

  it('increments counter', () => {
    renderApp();
    expect(screen.getByTestId('counter-value')).toHaveTextContent('0');
    fireEvent.click(screen.getByTestId('increment'));
    expect(screen.getByTestId('counter-value')).toHaveTextContent('1');
  });

  it('decrements counter', () => {
    renderApp();
    fireEvent.click(screen.getByTestId('increment'));
    fireEvent.click(screen.getByTestId('increment'));
    fireEvent.click(screen.getByTestId('decrement'));
    expect(screen.getByTestId('counter-value')).toHaveTextContent('1');
  });

  it('resets counter', () => {
    renderApp();
    fireEvent.click(screen.getByTestId('increment'));
    fireEvent.click(screen.getByTestId('increment'));
    fireEvent.click(screen.getByTestId('reset-counter'));
    expect(screen.getByTestId('counter-value')).toHaveTextContent('0');
  });

  it('adds a todo', () => {
    renderApp();
    fireEvent.change(screen.getByTestId('todo-input'), { target: { value: 'Buy milk' } });
    fireEvent.click(screen.getByTestId('add-todo'));
    expect(screen.getByTestId('todo-0')).toHaveTextContent('Buy milk');
    expect(screen.getByTestId('todo-count')).toHaveTextContent('1');
  });

  it('toggles a todo', () => {
    renderApp();
    fireEvent.change(screen.getByTestId('todo-input'), { target: { value: 'Test' } });
    fireEvent.click(screen.getByTestId('add-todo'));
    fireEvent.click(screen.getByTestId('toggle-0'));
    expect(screen.getByTestId('todo-0')).toHaveClass('todo-item--done');
  });

  it('removes a todo', () => {
    renderApp();
    fireEvent.change(screen.getByTestId('todo-input'), { target: { value: 'Test' } });
    fireEvent.click(screen.getByTestId('add-todo'));
    fireEvent.click(screen.getByTestId('remove-0'));
    expect(screen.getByTestId('todo-count')).toHaveTextContent('0');
  });
});

