import React, { createContext, useContext, useReducer, useMemo, useCallback, useRef } from 'react';

export type Action = { type: string; [key: string]: any };
export type Reducer<S = any> = (state: S, action: Action) => S;
export type Selector<S, T> = (state: S) => T;
export type Middleware = (state: any, action: Action, next: any) => void;

export function combineReducers(reducers: Record<string, Reducer>): Reducer {
  return (state: any, action: Action) => {
    const nextState: Record<string, any> = {};
    for (const key of Object.keys(reducers)) {
      nextState[key] = reducers[key](state[key], action);
    }
    return nextState;
  };
}

export function createStore<S>(rootReducer: Reducer<S>, initialState: S, middleware?: Middleware) {
  const StoreContext = createContext<{ state: S; dispatch: React.Dispatch<Action> } | null>(null);

  const StoreProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [state, rawDispatch] = useReducer(rootReducer, initialState);
    const stateRef = useRef(state);
    stateRef.current = state;

    const dispatch = useCallback((action: Action) => {
      if (middleware) {
        middleware(stateRef.current, action, rawDispatch);
      }
      rawDispatch(action);
    }, [rawDispatch]);

    const value = useMemo(() => ({ state, dispatch }), [state, dispatch]);
    return <StoreContext.Provider value={value}>{children}</StoreContext.Provider>;
  };

  function useSelector<T>(selector: Selector<S, T>): T {
    const ctx = useContext(StoreContext);
    if (!ctx) throw new Error('useSelector must be used within StoreProvider');
    return selector(ctx.state);
  }

  function useDispatch(): React.Dispatch<Action> {
    const ctx = useContext(StoreContext);
    if (!ctx) throw new Error('useDispatch must be used within StoreProvider');
    return ctx.dispatch;
  }

  return { StoreProvider, useSelector, useDispatch };
}
